var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이 스타디움에서 경기를 한다고……?","JPN":"このスタジアムで試合を……？","ENG":"This is where the match is going to be held...?","TWN":"在這個體育場裡進行比賽……？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엄청 커요! 사람들도 진짜 많고!","JPN":"めちゃくちゃ大きいです！　人も多いですし！","ENG":"It's super big! There are so many people!","TWN":"哇！這裡好大！人也超多！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"여기가 G 스타디움이야. 꿈이 시작되는 곳이지.","JPN":"ここはGスタジアムだ。夢が始まるところさ。","ENG":"This is G Stadium. It's where you take your first step toward your dream.","TWN":"這裡就是G體育場，是我們夢想的起點！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"이제까지 봤던 경기장과는 많이 다르군.","JPN":"これまで見てきた競技場とはだいぶ違うな。","ENG":"This is vastly different from the grounds we saw up until now.","TWN":"和我之前看過的體育場很不一樣呢。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카 말대로 여기서부터가 시작이거든요.","JPN":"ライカの言うとおり、ここからが始まりよ。","ENG":"Like Laika said, this is the first proper step.","TWN":"就像萊卡說的那樣，這裡才是真正的開始。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"본선은 예선과 포인트 최대치부터 달라요. 차원 함선도 기용하니까요.","JPN":"本戦は予選とポイントの最大値から異なるの。次元艦船も起用するから。","ENG":"The elimination round is nothing like the qualifiers. The maximum amount of points is increased, and they even dispatch dimensional ships.","TWN":"決賽和預賽的點數上限不同，還可以使用次元艦船。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"오디션 방송 같은 거 본 적 있어? 우린 이제 겨우 심사위원들 앞에 선 거야.","JPN":"オーディション番組とか見たことあるか？　私たちは、やっと審査委員の前に立ったんだ。","ENG":"Ever watched an audition before? Now we get to face the actual judges.","TWN":"你看過選秀節目嗎？我們現在才算是真正站到評審面前。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그, 그렇게 들으니까 단번에 와 닿네요…. 갑자기 긴장돼요.","JPN":"そ、そう聞くと一気に実感が湧きますね……急に緊張してきました。","ENG":"Th-that makes it sound too real... I'm getting anxious now.","TWN":"聽，聽你這麼一說，一下子就有感覺咧……突然好緊張喔。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_A","text":{"KOREA":"저쪽이다! 어서 가서 찍어!","JPN":"あっちだ！　早く撮れ！","ENG":"There! Take her photo, now!","TWN":"在那邊！快點過去拍照！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_B","text":{"KOREA":"기자입니다! 잠시만 지나가겠습니다! 좀 비켜 주세요!","JPN":"記者です！　ちょっと通ります！　どいてください！","ENG":"Excuse me, coming through! I'm a reporter! Move aside, please!","TWN":"我是記者！借過！請讓讓！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"갑자기 무슨 소란이야? 우리 찍으러 왔대?","JPN":"いきなり何の騒ぎなんだ？　私たちの撮影？","ENG":"What's going on? Are they here to take pictures of us?","TWN":"怎麼突然這麼熱鬧？是來拍我們的嗎？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저희는 안중에도 없어 보이던데요. 저쪽으로 다 몰려갔어요.","JPN":"私たちなど眼中にないみたいよ。みんなあっちに行ったもの。","ENG":"From the looks of it, they don't care who we are. They are all off towards that direction.","TWN":"完全沒把我們看在眼裡呢，一窩蜂衝到那邊去了。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어쩌면 유명인이 경기를 보러 왔는지도 몰라요! 구경하러 가요!","JPN":"もしかしたら、有名人が試合を見に来たのかもしれません！　行きましょう！","ENG":"Maybe someone famous has come to see the match! Let's go take a peek!","TWN":"說不定是有名人來看比賽！我們去看看吧！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"혹시 알파트릭스 회장님 아니야?","JPN":"ひょっとして、アルファトリックスの会長じゃない？","ENG":"Maybe it might be the President of Alphatrix?","TWN":"難道是阿爾法崔克斯會長？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"여기까지 올 만큼 한가한 상황은 아닐 텐데…?","JPN":"ここまで来るほど、暇な状況ではないはずだが……？","ENG":"I don't think she's got time to come all this way...","TWN":"她應該沒閒到有時間來這裡吧……？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저기 보세요! 기자들이 잔뜩 몰려 있어요!","JPN":"あっちを見てください！　記者さんがいっぱいです！","ENG":"Look there! The reporters are all gathered over there!","TWN":"看那邊！記者都圍在那裡！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"어? 저 사람은?","JPN":"あれ？　あの人は？","ENG":"Huh? That's...","TWN":"嗯？那個人是？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_C","text":{"KOREA":"스완 씨! 이번에 출연하시는 작품에 대해 한 말씀 부탁드립니다!","JPN":"スワンさん！　今度出演する作品について、一言お願いします！","ENG":"Swan! Please tell us about your newest movie!","TWN":"史旺！請談談你這次演出的作品！"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L37_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_D","text":{"KOREA":"최근 법정에 출두한 건틀렛 선수와의 열애설에 대해서 입장 표명해 주실 수 있나요!","JPN":"最近法廷に出頭したガントレット選手との熱愛報道について、立場を表明してくれませんか！","ENG":"Do you have anything to say about the scandal between you and the Gauntlet player who was recently in court?","TWN":"大家都在傳你和最近出庭的聖鎧選手在戀愛中，你能說說你的立場嗎？"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_E","text":{"KOREA":"올해 여우주연상 시상식에 불참하셨는데, 무슨 이유였습니까!","JPN":"今年の主演女優賞の授賞式には不参加でしたが、理由は何ですか！","ENG":"You didn't attend the award ceremony for this year's leading female actress. Why was that?","TWN":"今年你沒出席最佳女主角的頒獎典禮，請問有什麼特別的原因嗎？"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"세상에, 스완이야! 언제 여기 온 거지?","JPN":"ウソ、スワンだよ！　いつここに来たんだろう？","ENG":"Goodness, that's Swan! When did she arrive?","TWN":"哇，是史旺欸！她是什麼時候來這裡的？"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 스완이요?","JPN":"はい？　スワン？","ENG":"Huh? Swan?","TWN":"什麼？是史旺？"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사, 사사, 사장님! 사진기! 엄청 큰 사진기가 필요해요!","JPN":"しゃ、しゃしゃ、社長！　カメラ！　めちゃくちゃ大きいカメラが必要です！","ENG":"B-B-B-Boss! Camera! I need a camera, a big one, now!","TWN":"老，老老，老闆！照相機！我需要一個超大的照相機！"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게나 유명한 사람인가?","JPN":"そんなに有名な人なのか？","ENG":"Is she that famous?","TWN":"她很有名嗎？"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 국제 영화상을 매년 전부 독점하는 바람에 수상 거부까지 한 전설이에요!","JPN":"はい！　国際映画賞を毎年全部独り占めしちゃうせいで、受賞拒否までしたっていう伝説の人なんですよ！","ENG":"Yes! She's a living legend! She even refused to receive an award because she swept every award, in and out of the country every year!","TWN":"沒錯！史旺是傳奇人物欸！她每年都獨佔各大國際電影獎項而且還拒絕領獎！"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"헤에, 의외로 코치도 세상 돌아가는 일에 관심 없구나?","JPN":"へえ、意外とコーチも世間話に興味ないんだな？","ENG":"Huh, so you're not that much into mainstream media, Coach?","TWN":"哈，沒想到教練也不關注社會時事呢？"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"본인 관심사가 아니면 신경 쓰지 않는 거겠죠.","JPN":"自分が興味ないことなら、気にしないだけでしょ。","ENG":"He doesn't care about things that are not of his interest.","TWN":"應該是不在乎不感興趣的事吧？"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_CAMERA"},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"능력 있는 사람들은 그런 성격이 많대요.","JPN":"能力のある人たちに、そんな性格が多いらしいわ。","ENG":"They say a lot of influential people are like that.","TWN":"據說很多有能力的人都是這樣的性格。"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응……?","JPN":"うん……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님, 저 사람이랑도 아는 사이야? 사장님을 보고 웃는데?","JPN":"社長、あの人とも知り合いなの？　社長を見て笑ってるけど。","ENG":"Boss, do you know her? She's smiling at you.","TWN":"老闆，你認識那個人嗎？她剛才在朝老闆笑呢？"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"설마. 오늘 처음 보는 사이라네.","JPN":"まさか。今日初めて会うんだが。","ENG":"Of course not. This is the first time I've seen her.","TWN":"不會吧？我今天是第一次見到她。"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"아무리 그래도 만나는 사람들마다 접점이 있진 않아.","JPN":"いくらなんでも、出会う人全員と関わりがあるわけではない。","ENG":"Just because I have connections doesn't mean I know everyone.","TWN":"我的人脈沒有廣到跟每個人都有接觸。"},"stage":{"bg":"CHARADE_002","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_A","text":{"KOREA":"스완 씨! 그 미소의 의미는 뭔가요? 방금 질문과 무슨 연관 있습니까?","JPN":"スワンさん！　今の笑顔の意味は何ですか？　さっきの質問と何か関係があるんですか？","ENG":"Swan! Why are you smiling? Is it related to the question I asked?","TWN":"史旺！請問你剛才的微笑有什麼意思嗎？和剛才的問題有什麼關係嗎？"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_B","text":{"KOREA":"잠깐, 저기 있는 건 예선전 참가 팀 아니야?","JPN":"ちょっと、あそこにいるのって、予選の参加チームじゃないか？","ENG":"Wait, aren't those people over there playing for the qualifiers?","TWN":"等等，那不是預賽的參賽隊伍嗎？"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_C","text":{"KOREA":"거기 남성 분! 혹시 스완 씨와 무슨 관계십니까?!","JPN":"そこの男性の方！　スワンさんとはどんな関係ですか！？","ENG":"You there, mister! What is your relationship with Swan?","TWN":"那邊那位先生！他和史旺有什麼關係嗎？"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이, 이쪽으로 몰려온다!","JPN":"こ、こっちに来る！","ENG":"H-here they come!","TWN":"記者們，往這邊來了！"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님께 듣고 싶은 말이 많은 것 같은데요?! 둘러싸였다간 경기 전에 녹초가 되겠어요!","JPN":"社長に聞きたいことがたくさんあるみたいですよ！？　囲まれたら試合の前でどっと疲れちゃいます！","ENG":"They want to interview you, Boss! We'll get trampled even before the match starts!","TWN":"似乎是想要採訪老闆呢？！被包圍的話，比賽前就會被弄得筋疲力盡吧！"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 도망쳐야지.","JPN":"それなら、逃げよう。","ENG":"We should run, then.","TWN":"那快點逃吧。"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"알겠어요, 코치!","JPN":"わかりました、コーチ！","ENG":"All right, Coach!","TWN":"是，教練！"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"다들 서둘러요! 장비만 챙겨서 이동합니다!","JPN":"みんな、急いでください！　装備だけ取りまとめて、移動します！","ENG":"Everyone, hurry! Grab your equipment and move!","TWN":"大家動作快！拿著裝備快跑！"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"빌어먹을, 이게 갑자기 무슨 난리야?","JPN":"ちくしょう、いきなり何なんだよ！","ENG":"Crap, what's with all this nonsense?","TWN":"該死，怎麼突然變得這麼混亂？"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"대기실로 가! 거기라면 못 들어올 거야!","JPN":"控え室まで行って！　そこなら入ってこれないはずだから！","ENG":"Head towards the waiting room! We'll be safe there!","TWN":"大家去休息室！那裡記者應該進不去！"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_D","text":{"KOREA":"도망친다! 어서 쫓아가!","JPN":"逃げるぞ！　早く追え！","ENG":"They're running away! Get them!","TWN":"人跑掉咧！快追！"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_E","text":{"KOREA":"스완 씨, 오늘 경기를 보러 오신 이유가 뭐죠?","JPN":"スワンさん、今日の試合を見に来た理由は何ですか？","ENG":"Swan, why did you come to see today's match?","TWN":"史旺，你今天來看比賽的原因是什麼？"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_F","text":{"KOREA":"후원하는 팀이라도 있는 건가요? 평소 건틀릿에 흥미가 있으셨나요?","JPN":"後援するチームでもあるんですか？　普段からガントレットに興味はあったんですか？","ENG":"Is there a team you're rooting for? Were you always interested in the Gauntlet?","TWN":"是有你支持的隊伍嗎？你平時對聖鎧感興趣嗎？"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아뇨. 그렇지는 않습니다.","JPN":"いいえ。そうではありません。","ENG":"No. Not really.","TWN":"沒有，不感興趣。"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만……","JPN":"ですが……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"방금 막 흥미가 생겼어요.","JPN":"たった今、興味が湧きました。","ENG":"I've taken an interest just now.","TWN":"剛剛突然開始感興趣了。"},"stage":{"bg":"CHARADE_003","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"예─이! 설마 티케팅 실패했다고 이불 속에서 질질 짜고 있는 거 아니지?","JPN":"まったく！　まさかチケットをゲットできなかったからって、布団の中でシクシク泣いてるんじゃないよね？","ENG":"Eyyy! Hope no one's sobbing because they failed to get tickets for the match!","TWN":"哎—呀！大家不會因為搶票失利就躲在被子裡哭吧？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"걱정 마시라! 이 건틀렛의 요정, 베티 미치가 현장에 나와 있으니까☆","JPN":"ご心配無用！　このガントレットの妖精、ベティー・ミッチーが現場に来てるから☆","ENG":"Don't you all worry! Your Gauntlet fairy, Batty Mitchie, is here on the scene for you! ☆","TWN":"別擔心！聖鎧精靈，貝蒂·米奇就在現場☆！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이곳은 G 스타디움! 객석도 경기장도 뜨거운 열기로 후끈 달아오른 곳!","JPN":"ここはGスタジアム！　客席も競技場も、アツアツの熱気で熱く燃え上がってるところ！","ENG":"We are currently at G Stadium! Phew, the atmosphere here is on FIRE!","TWN":"這裡是G體育場！哇喔，觀眾席和賽場上都很火熱呢！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아휴, 덥다~ 이런 열기 속에선 밋치도 가드가 살짝 느슨해져 버릴지도~?","JPN":"もう、暑い～こんな熱気の中では、ミッチーもちょっとガードが緩くなっちゃうかも～？","ENG":"It's so hot in here... Maybe even Mitchie might loosen up a little in this heat, fu fuu!","TWN":"好熱喔～在這種火熱的氣氛裡，說不定米琪的防禦也會鬆懈一點點喔～？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하지─만☆ 경기에 나올 선수들은 방심해선 안 되겠지?","JPN":"でーも☆ 試合に出る選手たちは、気を抜いちゃダメだよね？","ENG":"But! ☆ That will be a big no-no for the players attending tonight, eh?","TWN":"但—是☆參加比賽的選手們可不能掉以輕心喔？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"조심 또 조심! 여기서 무릎 까졌다고 울다간 평생 넷튜브 박제형이니까!","JPN":"用心、用心！　ここで膝を擦りむいたからって泣いたら、一生ネットチューブに晒されるよ！","ENG":"Caution is key, fellas! You'll become a meme if you bawl your eyes out here!","TWN":"小心駛得萬年船！如果因為在這裡跌倒就哭哭，那影片可是會在網路上永遠流傳的喔！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"스타디움 경기장 구조는 다들 숙지했지?","JPN":"スタジアム競技場の構造、みんな熟知してるよね？","ENG":"Is everyone familiar with the stadium structure?","TWN":"體育場的賽場結構大家都熟悉了吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"각 건물들의 지하실을 통해 들어갈 수 있는 통로가 방어 측 거점으로 통해.","JPN":"各建物の地下室を通じて入れる通路が、防御側の拠点に繋がってる。","ENG":"There are passages that can be entered through the basement of each building, which leads to the defense base.","TWN":"各個建築的地下室都有通向防守方據點的通道。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"1차 저지는 건물들을 활용해서, 보급한 뒤의 2차 저지는 지하에서 이루어지는 흐름이야.","JPN":"1次阻止は建物を活用して、補給してからの2次阻止は地下で行われる流れだよ。","ENG":"The first blockade will be held using the buildings, and the second one will be held underground, after each team's supplies are replenished.","TWN":"這就表示著第一次攔截會發生在建築周邊，第二次則會在雙方都得到重新補給後的地下。"},"stage":{"bg":"BASEMENT","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"단, 이번 경기는 중간에 조명이 꺼지면서 5분간 암전으로 전환될 거야.","JPN":"ただし、今度の試合は途中で照明が消えて、5分間暗転になる。","ENG":"Keep in mind that there will be a five-minute lights-out event during the match!","TWN":"但是，這場比賽中途會關掉照明設備，轉換成5分鐘的夜戰模式。"},"stage":{"bg":"BASEMENT","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"주 조명은 여기, 방어 거점 바로 뒤에 있어.","JPN":"主照明はここ、防御拠点のすぐ後ろにある。","ENG":"The main lighting is here, right behind the defense base.","TWN":"主要照明在這裡，就在防守據點後面。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"암전 기믹이 끝난 직후가 반격 타이밍이야. 우리에게 허락된 유일한 이점이지.","JPN":"暗転ギミックが終わった直後が反撃するタイミングだよ。私たちに許された唯一の利点ね。","ENG":"Our chance for attacking back will be right after the lights-out gimmick. It's the only advantage we have.","TWN":"夜戰機關結束後就是反擊的時機，這也是我們唯一的優勢。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"처형식이 잘 보이라고 저기 세워 둔 게 아니라?","JPN":"処刑がよく見えるように、あっちに立たせておいたんじゃないのか？","ENG":"Don't you think that light is more of a spotlight for our execution?","TWN":"確定那個設備不是給我們公開處刑的聚光燈嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"준비했던 전술은 죄다 무용지물이지, 상대가 어디서 구르다 왔는지도 모르지.","JPN":"用意してた戦術は全部無駄になったし、相手はどんなやつらなのかさっぱりだし。","ENG":"Everything we prepared is useless, and we don't even know who our opponents are.","TWN":"先前準備的戰術完全派不上用場，對手也不知道是從哪冒出來的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠옷 바람으로 현장에 던져 놔도 이것보단 낫겠다.","JPN":"パジャマ姿で現場にぶち込まれても、これよりはマシだろ。","ENG":"I'd rather fight in my pajamas.","TWN":"我看我乾脆直接穿著睡衣上場。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아쉬워요. 제가 아니라 미나 선배였으면 상대가 누구든 전부 한 방 감일 텐데.","JPN":"残念ですね。私じゃなくてミナ先輩だったら、相手が誰でもみんな一発でやっつけられるはずなのに。","ENG":"What a shame. If it was Mina instead of me, they would all be taken down with one blow.","TWN":"真可惜，如果是米娜前輩的話，不管對手是誰都能一下子打趴吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"노엘 양. 소대장 대행은 부상자라네.","JPN":"ノエル君。小隊長代行は怪我人だ。","ENG":"Noelle. Please remember that your temporary commander is injured.","TWN":"洛艾兒，代理小隊長現在是病人喔。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 맞다! 그랬죠! 죄송해요! 선배!","JPN":"あっ、そうだ！　そうでしたね！　ごめんなさい！　先輩！","ENG":"Oh, right! Sorry, Mina!","TWN":"哎呀，對欸！對不起！前輩！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아냐. 나도 상대가 하는 짓이 마음에 드는 건 아니니까.","JPN":"いや。私も相手のやってることが気に入ってるわけじゃないから。","ENG":"Don't mention it. I don't like what they're doing either.","TWN":"沒事，我也不喜歡對方的做法。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"괜찮아요. 지금까지 계속 로비도 없이 싸웠으니까요. 조금 더 불리해졌을 뿐이에요.","JPN":"大丈夫です。これまでずっとロビー活動なしで戦ってきたんですから。さらにちょっとだけ不利になっただけです。","ENG":"It's okay. We've been fighting all this time without even lobbying. It's just a little harder this time.","TWN":"沒關係，之前我們也是在沒行賄的狀態下進行比賽的，現在情勢只有比之前更不利一點而已。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이렇게까지 했는데 저희가 이기면 그릴 파티는 폐업 확정이죠. 꼴 좋다.","JPN":"ここまでやっても私たちが勝つなら、グリルパーティーは廃業確定です。ざまあみろ。","ENG":"If we win this match, then Grill Party is doomed for sure. Suckers!","TWN":"反倒是他們搞這麼多小動作，如果還輸給我們的話，那格里爾派提真的就準備關門大吉吧。想到就開心。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐, 일단 아까 대기실을 염탐하면서 선수 명단을 슬쩍 확인해 봤는데….","JPN":"ま、とりあえずさっき控え室を探ってて、選手のリストをちらっと確認したんだけど……","ENG":"Well. I did take a peek at their entry list in the waiting room...","TWN":"嗯，剛才在休息室裡，我有偷看一下選手名單……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그릴 파티에서 못 본 얼굴들이 잔뜩 있더라. 아마 신형 장비를 입고 온 녀석들이겠지.","JPN":"グリルパーティーでは見なかった顔だらけだったよ。たぶん、新型の装備をつけてきたやつらだろ。","ENG":"Most of them were not from Grill Party. They're probably all suited up with state-of-the-art equipment.","TWN":"格里爾派提的小隊中有很多沒見過的生面孔。他們應該是穿著新型裝備來的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"신형 장비요?","JPN":"新型の装備ですか？","ENG":"State-of-the-art equipment?","TWN":"新型裝備？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"스틸레인의 표준 강화복과는 다른 것 같더군.","JPN":"スチールレインの標準強化服とは違うようだったな。","ENG":"They looked different from the standard power suits from Steel Lane.","TWN":"好像和鋼鐵之軀的標準強化服不一樣。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"네. 민간에 판매하기 전에 테스트용으로 공급한 모델 같아요.","JPN":"はい。民間に販売する前に、テスト用として供給したモデルみたいです。","ENG":"Yes. They looked like prototypes that were provided for testing before sales.","TWN":"沒錯，這應該是賣到民營市場前的測試型號。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"최신 트렌드에 맞췄으면 신체 능력 증강 기능이 메인이겠죠.","JPN":"最新のトレンドに合わせてるなら、身体能力を増強する機能がメインでしょう。","ENG":"If it's brand new, they would've probably focused on enhancing the physical abilities.","TWN":"如果是最新的那幾款，主要功能應該是增強體能。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우으, 그럼 몸싸움은 절대 못 당해낼 것 같은데….","JPN":"うう、じゃあ、取っ組み合いでは絶対敵わないかも……","ENG":"Ugh, I don't think I'm ever going to beat them in hand-to-hand combat now...","TWN":"唔呃，我們赤手空拳絕對打不過……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치, 한 가지 부탁드릴 게 있어요.","JPN":"コーチ、一つだけお願いがあります。","ENG":"Coach, there's something I need to ask of you.","TWN":"教練，我想拜託你一件事。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"강화복은 머리 쓰다듬기 1회권과 교환하지.","JPN":"強化服なら、頭を撫でる1回券と交換しよう。","ENG":"The power suit can be exchanged for a headpat ticket.","TWN":"強化服可以用摸頭1次券兌換。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"무슨 일인가?","JPN":"何かね？","ENG":"What is it?","TWN":"什麼事？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……그건 제 쪽에서 거절할게요.","JPN":"……それはこちらからお断りします。","ENG":"...I refuse.","TWN":"……我拒絕。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"경기 중에 실시간으로 지시를 내려 주세요. 전황은 스키너가 가르쳐 줄 거예요.","JPN":"試合中にリアルタイムで指示してください。戦況はスキナーが教えてくれます。","ENG":"Give us instructions in real-time throughout the match. Skinner will inform you of the situation.","TWN":"比賽期間請隨時下達指示。史金納會告訴你戰況。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"지휘권을 포기하겠다는 거야, 너?","JPN":"あんた、指揮権をあきらめるってことか？","ENG":"Are you giving up your commanding authority?","TWN":"你這是要放棄指揮權的意思？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"직무유기다!! 저 충격 받았어요!","JPN":"職務怠慢！！　ショックです！","ENG":"This is a dereliction of duty! I'm shocked!","TWN":"震驚！你這是怠忽職守欸！！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……진정해. 그런 게 아니야, 노엘.","JPN":"……落ち着いて。それは違うよ、ノエル。","ENG":"...Relax. It's different, Noelle.","TWN":"……你冷靜點，不是那樣的，洛艾兒。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 그럼요?","JPN":"え？　それじゃあ、どういうことですか？","ENG":"Huh? Then what is it?","TWN":"嗯？那是為什麼？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"기억 안 나? 시뮬레이터를 사용할 때 네가 말했잖아.","JPN":"覚えてないの？　シミュレーターを使ったときに、あなたが言ったこと。","ENG":"Don't you remember? You said it yourself when using the simulator.","TWN":"你不記得了嗎？你自己在使用模擬器時說過的話？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘은 싸울 줄 몰라요. 일반인인 저보다 체력도 약하구요.","JPN":"ノエルさんは戦い方をわかっていません。一般人である私より体力も足りないですし。","ENG":"Noelle doesn't know how to fight. She's weaker than me, a non-Counter.","TWN":"洛艾兒不會戰鬥，體力比我這個一般人還差。"},"stage":{"bg":"BASEMENT","bgm":"UI_PVP_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나름대로 재능은 있는 편이야. 3종 침식체에게 기습당한 용병들을 혼자 구출해냈으니까.","JPN":"それなりに才能はある方だよ。第3種侵食体に奇襲された傭兵たちを一人で助けたんだから。","ENG":"She's kind of talented, in fact. Noelle rescued a bunch of mercenaries who were attacked by a Category 3 C.O. on her own.","TWN":"她其實蠻有天分的，以前還曾經獨自救出被3類侵蝕體攻擊的傭兵。"},"stage":{"bg":"BASEMENT","bgm":"UI_PVP_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"3종에게서요? 노엘이……?","JPN":"第3種からですか？　ノエルさんが……？","ENG":"From a Category 3? That Noelle...?","TWN":"3類侵蝕體嗎？洛艾兒……？"},"stage":{"bg":"BASEMENT","bgm":"UI_PVP_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"에헤헤, 사장님의 지시 덕분이지만요.","JPN":"えへへ、社長が指示してくれたおかげですけどね。","ENG":"Eh he he, it's all thanks to Boss's orders.","TWN":"嘿嘿嘿，都是老闆的指示下得好。"},"stage":{"bg":"BASEMENT","bgm":"UI_PVP_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 혼자선 허둥거리기만 하다 당했을 거예요.","JPN":"私一人だったら、慌てるばかりでやられていたはずです。","ENG":"If I did it alone, I would've died hesitating.","TWN":"如果是我自己，可能只會手忙腳亂。"},"stage":{"bg":"BASEMENT","bgm":"UI_PVP_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저 애는 그냥 이기고 싶어서 저러는 거야.","JPN":"あの子はただ勝ちたいだけだよ。","ENG":"She just wants to win this match.","TWN":"費莉塞特只是想贏而已，"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"리더로서 전술을 결정할 수 있는 권리를 포기해서라도.","JPN":"リーダーとして戦術を決められる権利をあきらめてでも。","ENG":"Even if it means giving up her commanding authority.","TWN":"即使要放棄身為隊長的決定權。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"절박할수록, 버리는 것도 쉬워지니까.","JPN":"差し迫るほど、簡単に捨てることもできるようになる。","ENG":"The more desperate you are, the easier it is to let things go.","TWN":"越是急迫的時候，放棄一些東西就越容易。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"정말 그래도 괜찮겠나?","JPN":"本当にそれでも大丈夫かね？","ENG":"Are you sure?","TWN":"那樣真的沒關係嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네. 저는 원래 어른들을 믿지 않아요.","JPN":"はい。私は元々大人たちを信じてません。","ENG":"Yes. I never trust adults.","TWN":"……我本來是不相信大人的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어른들은 전부 거짓말쟁이에, 잔인하니까요.","JPN":"大人たちはみんな嘘つきで、残酷ですから。","ENG":"They are nothing but cruel liars.","TWN":"大人全都是不擇手段的騙子。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하지만 코치는….","JPN":"でも、コーチは……","ENG":"But you, Coach...","TWN":"但是教練……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치의 능력은 믿을 수 있다고 생각해요.","JPN":"コーチの能力は信じられると思います。","ENG":"I think I can count on your abilities.","TWN":"我覺得我可以相信教練的能力。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러니까 지시를 내려 주세요. 결승까지 갈 수 있도록.","JPN":"だから、指示を出してください。決勝まで行けるように。","ENG":"Please, give us orders. So that we can make it to the finals.","TWN":"所以請下達指示吧，讓我們打進決賽。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"예선 최종 경기는 어느덧 여러분이 기대하던 4회차!","JPN":"予選の最終試合は、いよいよ皆さんが楽しみにしてた4回目！","ENG":"It's the final match of the qualifiers! The fourth match you've all been waiting for!","TWN":"這裡是預賽最後一輪比賽！也是大家期待已久的第四輪比賽啦！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"중계용 드론들은 세팅 완료! 이어지는 양 팀의 입장!","JPN":"中継用のドローンはセット完了！　続きまして、両チームの入場！","ENG":"Streaming drones all set! Ah, we see the players entering!","TWN":"轉播用的無人機已經全部就定位！接下來是雙方隊伍進場！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"공격 팀! 떠오르는 루키였지만 사채업자의 방망이질에 프라이드가 개박살났던 그 그릴 파티!","JPN":"攻撃チーム！　新たなルーキーだったけど、貸金業者とひと悶着あってプライドが粉々になったあのグリルパーティー！","ENG":"Offensive team! The upcoming rookies that were battered down by a single iron pipe of a loan shark! Grill Party!","TWN":"進攻方！雖然是最近崛起的新人，卻被高利貸業者的鐵管打碎所有驕傲的格里爾派提！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_A","text":{"KOREA":"서포트 팀 준비 완료. 이번에 잘 되면 넷튜브에 데뷔하겠다는데.","JPN":"サポートチーム、準備完了。今回うまくいったらネットチューブでデビューするらしいぞ。","ENG":"Support team on standby. If things go well, they say they're going to make a big debut on NetTube.","TWN":"支援組準備完畢，這次成功的話，一定會在網路上爆紅。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L18_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_B","text":{"KOREA":"녀석들, 풋내기들 골탕 먹일 생각에 신났군.","JPN":"あいつら、新人をいじることができるからって、ウキウキしてるな。","ENG":"They look so excited to pull a prank on a bunch of young kids.","TWN":"嘿嘿嘿，一想到要讓小孩子吃癟我就很興奮。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_CHARADE_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_C","text":{"KOREA":"보는 눈이 많아. 잡담은 일 끝내고서 해.","JPN":"ここは人目が多い。雑談は仕事を終えてからにしろよ。","ENG":"We're not alone in here. Gossip later, after work is done.","TWN":"大家都在看我們，這些等結束後再說。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"RIFLE_CHARADE_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_CHARADE_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L21_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이어서 방어 팀!","JPN":"続けて、防御チーム！","ENG":"Moving on, defensive team!","TWN":"接下來是防守方！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"싸가지 없는 꼬맹이가 대빵인 카나리아 스쿼드!","JPN":"クソガキがチームを率いる、カナリア・スクワッド！","ENG":"Canary Squad, with a snobby child as their leader!","TWN":"由沒禮貌的小鬼領隊的，金絲雀小隊！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우와…. 경기장에서 듣는 환호성은 차원이 다르네요….","JPN":"うわ……競技場で聞く歓声は違いますね……","ENG":"Wow... the cheer sounds totally different from inside the arena...","TWN":"哇……賽場上傳來的歡呼聲也差太多……"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래. 다들 우리가 자빠지는 꼴을 보고 싶어서 안달이 났어.","JPN":"そう。みんな私たちがやられる姿を見たくて仕方ないんだよ。","ENG":"Yeah. They're all just waiting for us to make a fool of ourselves.","TWN":"就是說，大家都一副看衰我們的樣子。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러니까 정신 번쩍 들게 뒤통수를 세게 갈겨 주자고.","JPN":"だから、正気に戻るように後頭部を思いっきり殴ってやろうよ。","ENG":"So let's give them a memorable performance.","TWN":"所以我們打起精神來，讓所有人大吃一驚！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"피트 월, 들리나요?","JPN":"ピットウォール、聞こえますか？","ENG":"Pit wall, do you copy?","TWN":"礦壁，有聽見嗎？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>물론이지. 좋은 활약 기대하겠네.</color>","JPN":"<color=#ffd34c>もちろんだ。素敵な活躍、楽しみにしている。</color>","ENG":"<color=#ffd34c>Yes. I wish you good luck.</color>","TWN":"<color=#ffd34c>當然，我很期待你們的表現。</color>"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네. 잘 부탁드릴게요. 코치.","JPN":"はい。よろしくお願いします。コーチ。","ENG":"Thanks. Guide us to victory, Coach.","TWN":"好的，那就拜託你了，教練。"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L32_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하지만 놀랍게도 카나리아 스쿼드! 뭔가 단단히 각오한 표정!","JPN":"でも、驚くことにカナリア・スクワッド！　何か固く決意した顔！","ENG":"Oh, what's this? Canary Squad looks extremely determined!","TWN":"哇喔！金絲雀小隊一副心意已決的樣子！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"설마 진심으로 본선까지 올라갈 작정일까?","JPN":"まさか、本気で本戦まで行くつもりなのかな？","ENG":"Are they really planning on making it to the elimination round?","TWN":"難道她們真的打算打入決賽？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"궁금하다면 전원, 채널 고정!","JPN":"皆さん、気になっているならチャンネルはそのままで！","ENG":"If you're eager to find out, stay tuned!","TWN":"想知道的話，那就鎖定頻道別走開！"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"화장실 다녀오려면 지금이 기회야! 경기는 광고 후에 바로 시작된다구~?","JPN":"トイレに行きたかったら今がチャンス！　試合は、CMの後にすぐ始まっちゃうよ～？","ENG":"This is your last chance to go to the bathroom! The match starts right after the ad!","TWN":"現在就是去洗手間的最好的時機！廣告之後比賽馬上開始～？"},"stage":{"bg":"STADIUM","bgm":"UI_PVP_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};